func loadSessionsFromDisk() ([]*Session, error) {
	data, err := ioutil.ReadFile("sessions.gob")
	if err != nil {
		return nil, err
	}
	var sessions []*Session
	err = gob.NewDecoder(bytes.NewReader(data)).Decode(&sessions)
	if err != nil {
		return nil, err
	}
	return sessions, nil
}

func saveSessionsToDisk(sessions []*Session) error {
	var data bytes.Buffer
	enc := gob.NewEncoder(&data)
	err := enc.Encode(sessions)
	if err != nil {
		return err
	}
	return ioutil.WriteFile("sessions.gob", data.Bytes(), 0644)
}